import{_ as t,o as r,c as n,j as e,a as i,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const v=JSON.parse('{"title":"海灵Aventi","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/海灵Aventi .md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/海灵Aventi .md"}'),o={name:"4.资源分区/1.血统与训练/6.一次性血统/海灵Aventi .md"};function d(p,a,l,_,c,b){return r(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"海灵aventi",tabindex:"-1"},[i("海灵Aventi "),e("a",{class:"header-anchor",href:"#海灵aventi","aria-label":'Permalink to "海灵Aventi"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),s('<h1 id="海灵aventi-1" tabindex="-1">海灵Aventi <a class="header-anchor" href="#海灵aventi-1" aria-label="Permalink to &quot;海灵Aventi&quot;">​</a></h1><p>海灵Aventi<br> 一次性血统<br> 本质：魔幻<br> 价格：1000分<br> 特殊：不占用血统位<br> 「你小小的人类王国很有意思，但在古老海灵图帝国的荣光前，就要黯然失色了——无论是大浪袭来之前，或是之后。」————帛罗·阿比利修，流亡的海灵军阀。<br> 沈入海中的古帝国遗民，海灵调节了他们的新家乡，如今已在海陆之间展开了他们的探险。从任何有人烟的海岸，到海床下最深的沟壑，都有这支自视甚高的骄傲民族的踪迹。<br> 海灵的外表比起人类有点娇小。他们的体积修正为4，男性海灵通常比女性来得高壮一些。海灵的皮肤通常相当苍白，带着点蓝色到褐色间的阶调，他们有着蓝色或绿色的眼珠，以从浅棕色到淡金色的头发。海灵前臂和小腿上有着游泳用的小鳍，它们在离水时会折起来平贴着肌肤。<br> 海灵穿得很少而且朴素——多数仅供遮羞，有时更少。他们喜欢珍珠和黄金一类不需火鑄的柔软金属。海灵和人类一样在15岁成年，并且有很少的一部分能活过一世纪。</p><p>种族特性:<br> 水生：海灵是水生类人种族，海灵可以在水中及陆地上不受限制的呼吸。</p><p>速度: 海灵获得等同于基础移动速度的游泳速度。</p><p>水法术之力：魔法纽带连接着海灵与海灵特努，无尽的岁月中海神保护海灵免于灭亡。因此海灵施法者在水法术上拥有更强大的力量，一个海灵的施法者等级在有「水」描述的法术上额外获得1dp环境加值。</p><p>人类血统：对所有针对种族的效果，海灵视为人类。如同人类，只对人类有效的效果同样对海灵有效。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const A=t(o,[["render",d]]);export{v as __pageData,A as default};
